  AirDatepicker.prototype._build=function(){this.$datepicker=document.createElement('div');this.$datepicker.className='air-datepicker';this.$datepicker.hidden=true;this.$datepicker.innerHTML='<div class="air-datepicker-nav"><button type="button" class="air-datepicker-nav-action" data-prev>‹</button><div class="air-datepicker-nav-title"></div><button type="button" class="air-datepicker-nav-action" data-next>›</button></div><div class="air-datepicker-body"><div class="air-datepicker-body--day-names"></div><div class="air-datepicker-body--cells"></div></div><div class="air-datepicker-time" hidden><div class="air-datepicker-time-row"><span class="air-datepicker-time-value" data-time-value></span><input type="range" min="0" max="23" step="1" data-hours></div><div class="air-datepicker-time-row"><span></span><input type="range" min="0" max="59" step="1" data-minutes></div></div><div class="air-datepicker-buttons"></div>';document.body.appendChild(this.$datepicker);this.$title=this.$datepicker.querySelector('.air-datepicker-nav-title');this.$days=this.$datepicker.querySelector('.air-datepicker-body--day-names');this.$cells=this.$datepicker.querySelector('.air-datepicker-body--cells');this.$time=this.$datepicker.querySelector('.air-datepicker-time');this.$timeValue=this.$datepicker.querySelector('[data-time-value]');this.$hours=this.$datepicker.querySelector('[data-hours]');this.$minutes=this.$datepicker.querySelector('[data-minutes]');this.$buttons=this.$datepicker.querySelector('.air-datepicker-buttons');['ПН','ВТ','СР','ЧТ','ПТ','СБ','ВС'].forEach(function(d){var n=document.createElement('div');n.className='air-datepicker-body--day-name';n.textContent=d;this.$days.appendChild(n);},this);this._renderButtons();this.render();};
